parameters.jsCode:
// Healthcheck for the LlamaIndex memory worker pipeline.
// Push-only design: n8n never reaches out to Waza.
// To validate the scheduled timer path without SSH, we require a recent
// *incremental* run from host_origin=waza. A manual full backfill must not mask
// a broken timer.
const { Client } = require('pg');
const http = require('http');

function checkQdrant() {
  return new Promise((resolve) => {
    const req = http.get(
      'http://javisi_qdrant:6333/collections/memory_v1',
      { timeout: 5000 },
      (res) => {
        let d = '';
        res.on('data', (c) => d += c);
        res.on('end', () => {
          resolve({
            reachable: res.statusCode === 200,
            status: res.statusCode,
            body: d.slice(0, 200)
          });
        });
      }
    );
    req.on('error', (e) => resolve({ reachable: false, error: e.message }));
    req.on('timeout', () => {
      req.destroy();
      resolve({ reachable: false, error: 'timeout' });
    });
  });
}

async function checkRuns() {
  const client = new Client({
    host: 'postgresql',
    port: 5432,
    database: 'n8n',
    user: 'n8n',
    password: $env.DB_POSTGRESDB_PASSWORD
  });
  await client.connect();
  try {
    const latestResult = await client.query(`
      SELECT run_id, received_at, host_origin, mode, spool_size,
             qdrant_reachable, exit_code,
             EXTRACT(EPOCH FROM (NOW() - received_at)) / 3600.0 AS age_hours
      FROM memory_runs
      ORDER BY received_at DESC
      LIMIT 1
    `);
    const latestIncrementalResult = await client.query(`
      SELECT run_id, received_at, host_origin, mode, spool_size,
             qdrant_reachable, exit_code,
             EXTRACT(EPOCH FROM (NOW() - received_at)) / 3600.0 AS age_hours
      FROM memory_runs
      WHERE host_origin = 'waza' AND mode = 'incremental'
      ORDER BY received_at DESC
      LIMIT 1
    `);
    return {
      lastRun: latestResult.rows[0] || null,
      lastIncrementalRun: latestIncrementalResult.rows[0] || null,
    };
  } finally {
    await client.end();
  }
}

const maxAgeHours = Number($env.MEMORY_HEALTHCHECK_MAX_AGE_HOURS || '2');
const maxSpool = Number($env.MEMORY_HEALTHCHECK_MAX_SPOOL || '50');

const qdrant = await checkQdrant();

let lastRun = null;
let lastIncrementalRun = null;
let lastRunError = null;
try {
  const runState = await checkRuns();
  lastRun = runState.lastRun;
  lastIncrementalRun = runState.lastIncrementalRun;
} catch (e) {
  lastRunError = e.message;
}

const issues = [];

if (!qdrant.reachable) {
  issues.push(`qdrant_unreachable:${qdrant.error || qdrant.status}`);
}

if (lastRunError) {
  issues.push(`db_error:${lastRunError}`);
} else if (!lastRun) {
  issues.push('no_runs_recorded');
} else {
  if ((lastRun.spool_size ?? 0) > maxSpool) {
    issues.push(`spool_high:${lastRun.spool_size}`);
  }
  if (lastRun.qdrant_reachable === false) {
    issues.push('last_run_qdrant_unreachable');
  }
  if (lastRun.exit_code !== null && lastRun.exit_code !== 0) {
    issues.push(`last_run_exit_code:${lastRun.exit_code}`);
  }
}

if (!lastIncrementalRun) {
  issues.push('no_incremental_runs_recorded');
} else {
  const ageHours = Number(lastIncrementalRun.age_hours || 0);
  if (ageHours > maxAgeHours) {
    issues.push(`stale_incremental:last_run_${ageHours.toFixed(1)}h_ago`);
  }
}

const needsAlert = issues.length > 0;

return [{
  json: {
    status: needsAlert ? 'unhealthy' : 'healthy',
    checked_at: new Date().toISOString(),
    qdrant_reachable: qdrant.reachable,
    qdrant_detail: qdrant.error || qdrant.status,
    last_run: lastRun ? {
      run_id: lastRun.run_id,
      host_origin: lastRun.host_origin,
      mode: lastRun.mode,
      received_at: lastRun.received_at,
      age_hours: Number(lastRun.age_hours || 0).toFixed(2),
      spool_size: lastRun.spool_size,
      exit_code: lastRun.exit_code,
      worker_qdrant_reachable: lastRun.qdrant_reachable
    } : null,
    last_incremental_run: lastIncrementalRun ? {
      run_id: lastIncrementalRun.run_id,
      host_origin: lastIncrementalRun.host_origin,
      mode: lastIncrementalRun.mode,
      received_at: lastIncrementalRun.received_at,
      age_hours: Number(lastIncrementalRun.age_hours || 0).toFixed(2),
      spool_size: lastIncrementalRun.spool_size,
      exit_code: lastIncrementalRun.exit_code,
      worker_qdrant_reachable: lastIncrementalRun.qdrant_reachable
    } : null,
    thresholds: {
      max_age_hours: maxAgeHours,
      max_spool: maxSpool
    },
    issues,
    needs_alert: needsAlert
  }
}];

